{
  "grammar": [
    {
      "pattern": "V + 過 + O",
      "structure": ["Verb", "過", "Object"],
      "explanation_en": "Used to indicate that someone has experienced or done something before.",
      "title": "Experience with 過",
      "meaning": "Have done something before",
      "when_to_use": ["When talking about past experiences", "When asking if someone has ever done something"],
      "when_not_to_use": ["For actions that happened at a specific time (use 了 instead)", "For ongoing or habitual actions"],
      "pragmatic_notes": "In Taiwan, 過 is commonly used in casual conversation to share experiences, e.g., '你去過台北嗎？'",
      "word_order_notes": "Place 過 immediately after the verb and before the object.",
      "english_contrast": "English uses 'have/has + past participle' (e.g., 'I have eaten'), while Chinese uses V + 過.",
      "korean_contrast": "Korean uses '-아/어 본 적이 있다' (e.g., '먹어 본 적이 있어요'), similar to V + 過 + 的 + 經驗.",
      "negative_examples": [
        {
          "text": "我昨天吃過早餐。",
          "error": "This implies experience, but '昨天' specifies a time; use 了 instead."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我過吃牛肉麵。",
          "error": "過 must come after the verb, not before."
        }
      ],
      "transformation_drills": ["Change '我吃牛肉麵' to express experience: '我吃過牛肉麵。'"],
      "production_drills": ["Ask a partner: '你吃過滷肉飯嗎？' and answer based on your experience."],
      "common_error_patterns": ["Placing 過 before the verb", "Using 過 with specific time expressions"],
      "repair_feedback": {
        "word_order": "Remember: 過 goes right after the verb, like '吃過'.",
        "politeness": "This structure is neutral; add '請問' for polite questions.",
        "vocabulary": "Use 過 with action verbs like 吃, 喝, 去, 看."
      }
    },
    {
      "pattern": "正在 + V + O",
      "structure": ["正在", "Verb", "Object"],
      "explanation_en": "Used to describe an action that is currently in progress.",
      "title": "Ongoing Action with 正在",
      "meaning": "Is doing something right now",
      "when_to_use": ["When describing what someone is doing at this moment", "When answering '你在做什麼？'"],
      "when_not_to_use": ["For habitual actions (use 每天 or 常常)", "For completed actions"],
      "pragmatic_notes": "In Taiwan, 正在 is common in both formal and casual speech; sometimes shortened to 在 in quick conversation.",
      "word_order_notes": "Place 正在 before the verb; the object comes after the verb.",
      "english_contrast": "English uses 'am/is/are + verb-ing' (e.g., 'I am eating'), while Chinese uses 正在 + V.",
      "korean_contrast": "Korean uses '-고 있다' (e.g., '먹고 있어요'), similar to 正在 + V.",
      "negative_examples": [
        {
          "text": "我每天正在吃早餐。",
          "error": "正在 is for current actions, not habits; use '每天' with simple present."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我正在早餐吃。",
          "error": "Object should come after the verb, not before."
        }
      ],
      "transformation_drills": ["Change '我吃早餐' to show ongoing action: '我正在吃早餐。'"],
      "production_drills": ["Describe what you are doing now: '我正在看書。'"],
      "common_error_patterns": ["Using 正在 with habitual actions", "Placing object before verb"],
      "repair_feedback": {
        "word_order": "Put 正在 before the verb, like '我正在吃'.",
        "politeness": "This is neutral; add '不好意思' if interrupting.",
        "vocabulary": "Use with action verbs like 吃, 喝, 看, 聽."
      }
    },
    {
      "pattern": "V + 了 + O",
      "structure": ["Verb", "了", "Object"],
      "explanation_en": "Used to indicate that an action has been completed.",
      "title": "Completed Action with 了",
      "meaning": "Has done something",
      "when_to_use": ["When talking about actions that are finished", "When answering '你吃了嗎？'"],
      "when_not_to_use": ["For ongoing actions (use 正在)", "For future actions"],
      "pragmatic_notes": "In Taiwan, 了 is very common in daily speech; often used with time words like '昨天' or '剛才'.",
      "word_order_notes": "Place 了 after the verb and before the object.",
      "english_contrast": "English uses past tense (e.g., 'I ate'), while Chinese uses V + 了.",
      "korean_contrast": "Korean uses '-았/었다' (e.g., '먹었어요'), similar to V + 了.",
      "negative_examples": [
        {
          "text": "我明天吃了早餐。",
          "error": "了 is for completed actions; '明天' is future, so use '會' instead."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我了吃早餐。",
          "error": "了 must come after the verb, not before."
        }
      ],
      "transformation_drills": ["Change '我吃早餐' to show completion: '我吃了早餐。'"],
      "production_drills": ["Tell your partner what you ate today: '我吃了牛肉麵。'"],
      "common_error_patterns": ["Using 了 with future time", "Placing 了 before the verb"],
      "repair_feedback": {
        "word_order": "Put 了 after the verb, like '吃了'.",
        "politeness": "This is neutral; use '請問' for polite questions.",
        "vocabulary": "Use with action verbs like 吃, 喝, 去, 買."
      }
    }
  ]
}
